var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저쪽도 문제가 심각한 모양이네.","JPN":"向こうの状況も相当厳しいんだね。","ENG":"Sounds like things are pretty bad over there too.","TWN":"那邊的問題好像也很嚴重呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그럴 만도 하죠.","JPN":"まあ、それもそのはずでしょう。","ENG":"Haha, I bet.","TWN":"哈哈，怎麼可能不嚴重。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우리와는 관할 구역의 넓이가 차원이 다를 테니까요.","JPN":"僕たちとは、管轄区域の広さがまるで違うはずなので。","ENG":"Their jurisdiction is far more extensive than what we usually deal with.","TWN":"他們和我們管轄區域的範圍是不同次元的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 스승님. 대체 실비아 양까지 움직여 가면서 무슨 정보를 찾으신 겁니까?","JPN":"ところで師匠。シルビアさんに\\n頼ってまで、いったいどんな情報を探していたんですか。","ENG":"By the way, Master. What is it that you're looking for that you enlisted Sylvia’s assistance?","TWN":"話說回來，師父，到底是要找什麼資料，竟然要出動希爾維亞小姐？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 그건 제가 설명해 드릴게요.","JPN":"あ、それは私のほうから説明します。","ENG":"Oh, I can explain that.","TWN":"啊，這個我來解釋一下。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"몇 시간 전, 이상 침식 현상이 벌어진 직후에 외교 라인을 통해 쿠퍼 양으로부터 특정 초상현상에 관한 사건 기록을 검색해 달라는 연락을 받았습니다.","JPN":"数時間前、異常侵食現象が起きた直後に、外交筋を通じて\\nクーパーさんから特定の超常現象に関する事件記録を調査してほしいとの連絡を受けました。","ENG":"A few hours ago, right after the Counterside Effect began, we got word through diplomatic channels that Ms. Cooper requested a search of certain supernatural incidents.","TWN":"異常侵蝕現象發生之後，就在幾個小時前，庫博小姐透過外交部門希望我們幫忙搜索特定異常現象的事件。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저희 부서에도 협조 요청이 들어왔는데, 마침 저희가 수사 중이던 사건 중에 관련 있어 보이는 게 있어서 말이죠.","JPN":"うちの部署にも協力要請が入ってきたのですが、ちょうど私たちが捜査中だった事件と関連がありそうでして。","ENG":"They even reached out to our office, and it just so happened that we've been working on a similar case.","TWN":"因為我們正在搜查的事件中有相關資訊，所以我們部門也收到了協助請求。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 사건을 찾아 달라고 한 건데?","JPN":"どんな事件を調べて欲しいと言われたの？","ENG":"What incidents was she searching for exactly?","TWN":"你們要調查什麼事件？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>부활</color>입니다.","JPN":"<color=#ffd34c>復活</color>です。","ENG":"<color=#ffd34c>Resurrection</color>.","TWN":"是<color=#ffd34c>復活事件</color>。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정확히는 최근 2년 이내에, 카운터가 아닌 일반인에게서 발생한 대규모의 부활.","JPN":"厳密にはここ2年以内に、カウンターではなく一般人に起きた大規模な復活現象。","ENG":"Specifically, the mass resurrection of ordinary, non-Counter folks that occurred within the past two years.","TWN":"準確的說是最近2年內，在非制裁者的一般人中發生的大規模復活事件。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"혹은 그에 준하는 초재생 현상에 대한 사건 기록입니다.","JPN":"またはそれに準ずる超再生現象についての事件記録です。","ENG":"Or other records on similar supernatural regeneration short of outright resurrection.","TWN":"或者是超再生現象的相關記錄。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오....... 그런 일이 있었나요?","JPN":"ほほう……そんなことがあったのですか？","ENG":"Ooh... So did you find anything?","TWN":"哦……還有這種事情嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"대략 1년쯤 전부터 암시장을 통해 급속히 퍼져나가기 시작한 약물이 있습니다.","JPN":"1年くらい前から闇市で急速に普及した薬があります。","ENG":"There’s this drug that’s been spreading rapidly through black market for about a year now.","TWN":"大概1年前，有一種藥物通過黑市，開始在世間快速流行。"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이름은 <color=#ffd34c>엘릭서</color>.","JPN":"名前は、<color=#ffd34c>エリクサー</color>。","ENG":"It's called <color=#ffd34c>Elixir</color>.","TWN":"藥名是<color=#ffd34c>聖水</color>。"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"정확한 조제법은 알 수 없지만......","JPN":"正確な調剤方法はわかりませんが……","ENG":"We’re not exactly sure how it's made...","TWN":"確切的調製方法雖然不太清楚……"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};